/// Projector that updates User projection from events
pub struct UserProjector<R: UserProjectionRepository> {
    repository: Arc<R>,
}

impl<R: UserProjectionRepository> UserProjector<R> {
    /// Create a new projector
    pub fn new(repository: Arc<R>) -> Self {
        Self { repository }
    }

    /// Rebuild all projections from event history
    pub async fn rebuild(&self) -> Result<u64> {
        self.repository.rebuild_all().await
    }

    /// Process a stored event from the event store
    ///
    /// This method dispatches the event to the appropriate handler based on event type.
    /// Returns Ok(true) if the event was processed, Ok(false) if it was skipped.
    pub async fn process_stored_event(&self, event: &crate::infrastructure::event_store::StoredEvent) -> Result<bool>
    where
        Self: UserEventHandler,
    {
        let sequence = event.sequence;

        match event.event_type.as_str() {
            "UserCreatedEvent" => {
                let created: UserCreatedEvent = serde_json::from_value(event.payload.clone())?;
                self.on_created(created, sequence).await?;
                Ok(true)
            }
            "UserUpdatedEvent" => {
                let updated: UserUpdatedEvent = serde_json::from_value(event.payload.clone())?;
                self.on_updated(updated, sequence).await?;
                Ok(true)
            }
            "UserDeletedEvent" => {
                let deleted: UserDeletedEvent = serde_json::from_value(event.payload.clone())?;
                self.on_deleted(deleted, sequence).await?;
                Ok(true)
            }
            _ => Ok(false), // Event type not handled by this projector
        }
    }
}

#[async_trait]
impl<R: UserProjectionRepository> UserEventHandler for UserProjector<R> {

    async fn on_created(&self, event: UserCreatedEvent, sequence: i64) -> Result<()> {
        let mut projection = UserProjection::new(
            event.id,
            event.username,
            event.email,
            event.password_hash,
            event.status,
            event.email_verified,
            event.failed_login_attempts,
            event.locked_until,
            event.last_login,
            event.metadata
        );

        // Track the event sequence for this projection
        projection.apply_event(sequence);

        self.repository.save(&projection).await
    }

    async fn on_updated(&self, event: UserUpdatedEvent, sequence: i64) -> Result<()> {
        if let Some(mut projection) = self.repository.find_by_id(event.id).await? {
            // Apply updates from event
            projection.username = event.username;
            projection.email = event.email;
            projection.password_hash = event.password_hash;
            projection.status = event.status;
            projection.email_verified = event.email_verified;
            projection.failed_login_attempts = event.failed_login_attempts;
            projection.locked_until = event.locked_until;
            projection.last_login = event.last_login;
            projection.metadata = event.metadata;
            // Track the event sequence for this projection
            projection.apply_event(sequence);

            self.repository.save(&projection).await?;
        }

        Ok(())
    }

    async fn on_deleted(&self, event: UserDeletedEvent, _sequence: i64) -> Result<()> {
        self.repository.delete(event.id).await
    }
}

